solution: ```class Solution {
public:
    int repeatedStringMatch(string a, string b) {
        int m = a.size(), n = b.size();
        int minRep = (n + m - 1) / m;
        string s;
        for (int i = 0; i < minRep; ++i) s += a;
        if (s.find(b) != string::npos) return minRep;
        s += a;
        if (s.find(b) != string::npos) return minRep + 1;
        return -1;
    }
};
